from flask import Flask, request, redirect, url_for, flash
import os
from werkzeug.utils import secure_filename
from PIL import Image
import uuid

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
MAX_FILE_SIZE = 5 * 1024 * 1024  # 5MB
MAX_IMAGE_DIMENSION = 2000  # 2000x2000 pixels

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE

# Create upload directory if it doesn't exist
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def validate_and_process_image(file_path):
    try:
        # Open and validate image
        with Image.open(file_path) as img:
            # Check image dimensions
            if img.width > MAX_IMAGE_DIMENSION or img.height > MAX_IMAGE_DIMENSION:
                return False, "Image dimensions too large"
            
            # Convert to RGB if necessary (for JPEG)
            if img.mode in ('RGBA', 'LA', 'P'):
                img = img.convert('RGB')
            
            # Save with compression
            img.save(file_path, 'JPEG', quality=85, optimize=True)
            
        return True, "Image processed successfully"
    except Exception as e:
        return False, f"Image processing failed: {str(e)}"

@app.route('/upload', methods=['POST'])
def upload_file():
    # Check if file was submitted
    if 'file' not in request.files:
        flash('No file selected')
        return redirect(request.url)
    
    file = request.files['file']
    
    # Check if file is empty
    if file.filename == '':
        flash('No file selected')
        return redirect(request.url)
    
    # Validate file
    if file and allowed_file(file.filename):
        # Generate secure filename
        filename = secure_filename(file.filename)
        # Add UUID to prevent filename conflicts
        name, ext = os.path.splitext(filename)
        unique_filename = f"{name}_{uuid.uuid4().hex}{ext}"
        
        # Save file temporarily
        temp_path = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(temp_path)
        
        # Validate and process image
        success, message = validate_and_process_image(temp_path)
        
        if not success:
            # Remove temporary file
            os.remove(temp_path)
            flash(message)
            return redirect(request.url)
        
        # Move to final location with secure name
        final_path = os.path.join(app.config['UPLOAD_FOLDER'], f"profile_{uuid.uuid4().hex}.jpg")
        os.rename(temp_path, final_path)
        
        flash('Profile picture uploaded successfully')
        return redirect(request.url)
    
    else:
        flash('Invalid file type. Only PNG, JPG, JPEG, and GIF files are allowed.')
        return redirect(request.url)

if __name__ == '__main__':
    app.run(debug=False)